import (
	"crypto/rand"
	"encoding/base64"
	"math/rand"
	"time"
)

func generateRandomSessionToken() string {
	b := make([]byte, 32)
	rand.Seed(time.Now().UnixNano())
	rand.Read(b)
	return base64.RawURLEncoding.EncodeToString(b)
}